function SearchGrid() {
    var input, filter, table, tr, td, i, tds, isDisplay = false, ths;
    input = document.getElementById("searchby");
    filter = input.value.toUpperCase();
    table = document.getElementById("grid");
    tr = table.getElementsByTagName("tr");
    for (i = 0; i < tr.length; i++) {
        // tds = tr[i].getElementsByTagName("td");
        tds = tr[i].getElementsByClassName("Searchable");
        for (var j = 0; j < tds.length; j++) {
            td = tr[i].getElementsByTagName("td")[j];
            if (td) {
                if (td.innerHTML.toUpperCase().indexOf(filter) > -1) {
                    isDisplay = true;
                    break;
                } else {
                    isDisplay = false;
                }
            }
        }
        if (isDisplay) {
            tr[i].style.display = "";
        } else {
            ths = tr[i].getElementsByTagName("th");
            if (ths == undefined || ths.length == 0) {
                tr[i].style.display = "none";
            }
        }

    }
}

function SearchGridCallByID(VarGridId) {

    var input, filter, table, tr, td, i, tds, isDisplay = false, ths;
    input = document.getElementById("searchby");

    filter = input.value.toUpperCase();
    table = document.getElementById(VarGridId.id);
    tr = table.getElementsByTagName("tr");
    for (i = 0; i < tr.length; i++) {
        tds = tr[i].getElementsByTagName("td");
        for (var j = 0; j < tds.length; j++) {
            td = tr[i].getElementsByTagName("td")[j];
            if (td) {
                if (td.innerHTML.toUpperCase().indexOf(filter) > -1) {
                    isDisplay = true;
                    break;
                } else {
                    isDisplay = false;
                }
            }
        }
        if (isDisplay) {
            tr[i].style.display = "";
        } else {
            ths = tr[i].getElementsByTagName("th");
            if (ths == undefined || ths.length == 0) {
                tr[i].style.display = "none";
            }
        }

    }
}

