//// Allow only enter numeric text to textbox 
$('body').on('keypress', '.NumberTxt', function (e) {
    if (e.keyCode != 46 && e.keyCode > 31 && (e.keyCode < 48 || e.keyCode > 57)) {
        return false;
    }
});

function enableDataTable(tableId, pagination, searching, ordering, bInfo) {
    disableDataTable(tableId);

    $(tableId).dataTable({
        "bInfo": bInfo,
        "paging": pagination,
        "ordering": ordering,
        "searching": searching
    });
}

//-------------Disable Data Table Functions---------------
function disableDataTable(tableId) {
    $(tableId).DataTable().destroy();
}


