function FormatAmount(org_value) {

    var Amount = parseFloat(org_value.trim().replace(/,/g, '')).toFixed(2);
    var returnVal = '';
    if (Amount.toString() == "NaN") {
        returnVal = '0.00';
    }
    else {
        returnVal = Number(parseFloat(Amount).toFixed(2)).toLocaleString('en', { minimumFractionDigits: 2 });

    }
    return returnVal;
}


function ReFormatAmountByID(ControlID) {
    return parseFloat($('#' + ControlID).val().trim().replace(/,/g, '')).toFixed(2);
}

function ReFormatAmountByClass(ControlClass) {
    return parseFloat($('.' + ControlClass).val().trim().replace(/,/g, '')).toFixed(2);
}